package be.schaubroeck.lpb.rkm.rekenmotor;

import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementManager;
import be.schaubroeck.lpb.tools.AardKodeExtensie;
import be.schaubroeck.lpb.tools.Money;
import lombok.extern.slf4j.Slf4j;

import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.LOONELEMENT_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.PERSOON_INHOUDING_BESLAG_OP_LOON;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.PERSOON_INHOUDING_ONDERHOUDSGELD;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenInfoKey.LOONBESLAG_IBAN;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenInfoKey.LOONBESLAG_NAAM_SCHULDEISER;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenInfoKey.LOONBESLAG_OPMERKING;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenNettoKey.NETTO_KEY;

@Slf4j
public class FixManueleTussenkomstBeslagOpLoon extends AbstractRekenCommand {

    @Override
    protected boolean execute(RekenContext mainContext) {
        log.debug("Fix Manuele Tussenkomst Beslag Op Loon");
        BeslagOpLoonInfo onderhoudsgeld = mainContext.getUnchecked(PERSOON_INHOUDING_ONDERHOUDSGELD);
        BeslagOpLoonInfo beslagOpLoon = mainContext.getUnchecked(PERSOON_INHOUDING_BESLAG_OP_LOON);
        LoonElementManager manager = mainContext.getUnchecked(LOONELEMENT_MANAGER_KEY);
        for (LoonElement element : manager.getPersoonsElementen()) {
            vulBeslagOpLoonInfo(element, onderhoudsgeld);
            vulBeslagOpLoonInfo(element, beslagOpLoon);
        }
        return CONTINUE_PROCESSING;
    }

    private void vulBeslagOpLoonInfo(LoonElement element, BeslagOpLoonInfo info) {
        AardKodeExtensie loonCode = element.getAardKodeExtensie();
        String beneficiary = element.getPropertyUnchecked(LOONBESLAG_NAAM_SCHULDEISER);
        Money netto = element.getPropertyMoney(NETTO_KEY);
        if (info != null && info.getLoonCode().equals(loonCode) && netto.signum() != 0 && beneficiary == null) {
            element.putProperty(LOONBESLAG_NAAM_SCHULDEISER, info.getBeneficiary());
            element.putProperty(LOONBESLAG_IBAN, info.getIban());
            element.putProperty(LOONBESLAG_OPMERKING, info.getOpmerking());
        }
    }

}
